import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import axios from 'axios';
import { UploadCloud, Loader2, FileSpreadsheet, CheckCircle, AlertTriangle } from 'lucide-react';
import { generarNombreImagen } from '../utils/helpers';

const CargaMasiva = ({ localId, onComplete }) => {
  const [loading, setLoading] = useState(false);
  const [status, setStatus] = useState(null); // Para dar feedback visual de éxito

  const handleFileUpload = (e) => {
    const file = e.target.files[0];
    if (!file || !localId) return;

    setLoading(true);
    setStatus(null);
    const reader = new FileReader();

    reader.onload = async (event) => {
      try {
        const bstr = event.target.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws);

        const productosProcesados = data.map(prod => {
          // Extraemos y aseguramos que existan strings para el helper
          const tipo = prod.tipo || '';
          const marca = prod.marca || '';
          const contenido = prod.contenido || '';

          return {
            producto: `${tipo} ${marca} ${contenido}`.trim(),
            categoria: prod.categoria || 'Almacén',
            precioNuevo: Number(prod.precioNuevo) || 0,
            precioViejo: Number(prod.precioViejo) || 0,
            stock: Number(prod.stock || 0),
            peso: Number(prod.peso || 0),
            fechaVencimiento: prod.fechaVencimiento,
            // AQUÍ: Ahora usa la lógica blindada de tu nuevo helper.js
            publicId: generarNombreImagen(tipo, marca, contenido),
            local: localId
          };
        });

        const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';
        
        await axios.post(`${API_URL}/api/ofertas/bulk`, {
          productos: productosProcesados,
          localId: localId
        });

        setStatus({ type: 'success', msg: `${data.length} productos cargados con éxito.` });
        if (onComplete) onComplete();
      } catch (error) {
        console.error(error);
        setStatus({ type: 'error', msg: "Error en el formato del Excel." });
      } finally {
        setLoading(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  return (
    <div style={cardStyle}>
      <div style={headerCarga}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
          <FileSpreadsheet size={22} color="#0284c7" />
          <h4 style={{ margin: 0, color: '#0369a1', fontWeight: '700' }}>Importar Inventario</h4>
        </div>
        {status && (
          <div style={status.type === 'success' ? successLabel : errorLabel}>
            {status.type === 'success' ? <CheckCircle size={14} /> : <AlertTriangle size={14} />}
            {status.msg}
          </div>
        )}
      </div>

      <label style={{ ...dropZone, opacity: loading ? 0.6 : 1 }}>
        {loading ? (
          <Loader2 className="animate-spin" color="#0284c7" />
        ) : (
          <UploadCloud size={28} color="#0284c7" />
        )}
        <div style={{ textAlign: 'left' }}>
          <span style={dropTitle}>
            {loading ? 'Sincronizando con la nube...' : 'Arrastra o selecciona tu Excel'}
          </span>
          <p style={dropSubtitle}>Formato soportado: .xlsx, .xls</p>
        </div>
        <input 
          type="file" 
          accept=".xlsx, .xls" 
          onChange={handleFileUpload} 
          style={{ display: 'none' }} 
          disabled={loading} 
        />
      </label>
    </div>
  );
};

// --- ESTILOS MEJORADOS ---
const cardStyle = { 
  background: '#f0f9ff', 
  padding: '24px', 
  borderRadius: '24px', 
  border: '1px solid #bae6fd', 
  marginBottom: '30px',
  boxShadow: '0 4px 12px rgba(2, 132, 199, 0.05)'
};

const headerCarga = { 
  display: 'flex', 
  justifyContent: 'space-between', 
  alignItems: 'center', 
  marginBottom: '15px' 
};

const dropZone = { 
  display: 'flex', 
  alignItems: 'center', 
  justifyContent: 'center', 
  gap: '20px', 
  cursor: 'pointer', 
  padding: '25px', 
  background: 'white', 
  borderRadius: '16px', 
  border: '2px dashed #7dd3fc', 
  transition: 'all 0.3s ease' 
};

const dropTitle = { display: 'block', fontWeight: '700', fontSize: '1rem', color: '#0c4a6e' };
const dropSubtitle = { margin: 0, fontSize: '0.8rem', color: '#64748b' };

const successLabel = { display: 'flex', alignItems: 'center', gap: '5px', color: '#059669', fontSize: '0.85rem', fontWeight: '600', background: '#ecfdf5', padding: '5px 12px', borderRadius: '10px' };
const errorLabel = { display: 'flex', alignItems: 'center', gap: '5px', color: '#dc2626', fontSize: '0.85rem', fontWeight: '600', background: '#fef2f2', padding: '5px 12px', borderRadius: '10px' };

export default CargaMasiva;
